it("should keep a live cell with 3 live neighbors alive (survival)", () => {
  // ###   <- (0,0), (1,0), (2,0)
  // .#.   <- (1,1) has exactly 3 live neighbors -> survives
  const nextGen = nextGeneration([
    [0, 0],
    [1, 0],
    [2, 0],
    [1, 1],
  ]);
  expect(nextGen).toContainEqual([1, 1]);
});
